// DenyAction: prevent deletion of Log Analytics workspace
{
  "mode": "All",
  "displayName": "Prevent deletion of production Log Analytics workspaces",
  "parameters": {
    "workspaceNamePrefix": {
      "type": "String",
      "metadata": { "displayName": "Workspace name prefix to protect" }
    }
  },
  "policyRule": {
    "if": {
      "allOf": [
        { "field": "type", "equals": "Microsoft.OperationalInsights/workspaces" },
        { "field": "name", "like": "[concat(parameters('workspaceNamePrefix'), '*')]" }
      ]
    },
    "then": {
      "effect": "denyAction",
      "details": {
        "actionNames": ["delete"],
        "cascadeBehaviors": {
          "resourceGroup": "deny"
        }
      }
    }
  }
}

// DenyAction on a Key Vault: block deletion AND cascading deletes from RG deletion
{
  "if": {
    "field": "type",
    "equals": "Microsoft.KeyVault/vaults"
  },
  "then": {
    "effect": "denyAction",
    "details": {
      "actionNames": ["delete"],
      "cascadeBehaviors": {
        "resourceGroup": "deny"
      }
    }
  }
}

// Policy definition with a switchable effect parameter
{
  "mode": "Indexed",
  "displayName": "Require specific VM SKUs",
  "parameters": {
    "effect": {
      "type": "String",
      "defaultValue": "Deny",
      "allowedValues": ["Audit", "Deny", "Disabled"],
      "metadata": { "displayName": "Effect" }
    },
    "allowedSkus": {
      "type": "Array",
      "defaultValue": ["Standard_D2s_v3", "Standard_D4s_v3", "Standard_D8s_v3"],
      "metadata": { "displayName": "Allowed VM SKUs" }
    }
  },
  "policyRule": {
    "if": {
      "allOf": [
        { "field": "type", "equals": "Microsoft.Compute/virtualMachines" },
        { "field": "Microsoft.Compute/virtualMachines/sku.name",
          "notIn": "[parameters('allowedSkus')]" }
      ]
    },
    "then": {
      "effect": "[parameters('effect')]"
    }
  }
}

// Assignment for production: effect=Deny (full enforcement)
// Assignment for dev:        effect=Audit (visibility without blocking)
// Assignment for sandbox:    effect=Disabled (no evaluation — total freedom)

# DenyAction policy to protect production Key Vaults
resource "azurerm_policy_definition" "protect_kv" {
  name         = "denyaction-protect-prod-keyvaults"
  policy_type  = "Custom"
  mode         = "All"
  display_name = "Prevent deletion of production Key Vaults"

  policy_rule = jsonencode({
    if = {
      allOf = [
        { field = "type", equals = "Microsoft.KeyVault/vaults" },
        { field = "tags['environment']", equals = "production" }
      ]
    }
    then = {
      effect = "denyAction"
      details = {
        actionNames = ["delete"]
        cascadeBehaviors = { resourceGroup = "deny" }
      }
    }
  })
}

resource "azurerm_management_group_policy_assignment" "protect_kv" {
  name                 = "protect-prod-kvs"
  management_group_id  = var.corp_mg_id
  policy_definition_id = azurerm_policy_definition.protect_kv.id
  # No identity needed — DenyAction is synchronous like Deny
}

# Policy with effect parameter, Disabled used for sandbox environments
resource "azurerm_policy_definition" "require_encryption" {
  name         = "require-storage-encryption"
  policy_type  = "Custom"
  mode         = "Indexed"
  display_name = "Require storage account encryption"

  parameters = jsonencode({
    effect = {
      type         = "String"
      defaultValue = "Deny"
      allowedValues = ["Audit", "Deny", "Disabled"]
    }
  })

  policy_rule = jsonencode({
    if = {
      allOf = [
        { field = "type", equals = "Microsoft.Storage/storageAccounts" },
        { field = "Microsoft.Storage/storageAccounts/encryption.keySource",
          notEquals = "Microsoft.Keyvault" }
      ]
    }
    then = { effect = "[parameters('effect')]" }
  })
}

# Sandbox assignment — fully disabled
resource "azurerm_subscription_policy_assignment" "require_encryption_sandbox" {
  name                 = "require-encryption-sandbox"
  subscription_id      = var.sandbox_subscription_id
  policy_definition_id = azurerm_policy_definition.require_encryption.id

  parameters = jsonencode({
    effect = { value = "Disabled" }
  })
}

// Initiative containing both DenyAction and Deny policies
{
  "displayName": "Platform baseline: write + delete protection",
  "parameters": {
    "protectLawWorkspacesEffect": {
      "type": "String",
      "defaultValue": "denyAction",
      "allowedValues": ["denyAction", "Disabled"]
    },
    "protectKeyVaultsEffect": {
      "type": "String",
      "defaultValue": "denyAction",
      "allowedValues": ["denyAction", "Disabled"]
    },
    "denyPublicStorageEffect": {
      "type": "String",
      "defaultValue": "Deny",
      "allowedValues": ["Audit", "Deny", "Disabled"]
    }
  },
  "policyDefinitions": [
    {
      "policyDefinitionId": "/providers/Microsoft.Management/managementGroups/mg-corp/providers/Microsoft.Authorization/policyDefinitions/protect-prod-law-workspaces",
      "parameters": {
        "effect": { "value": "[parameters('protectLawWorkspacesEffect')]" }
      }
    },
    {
      "policyDefinitionId": "/providers/Microsoft.Management/managementGroups/mg-corp/providers/Microsoft.Authorization/policyDefinitions/denyaction-protect-prod-keyvaults",
      "parameters": {
        "effect": { "value": "[parameters('protectKeyVaultsEffect')]" }
      }
    },
    {
      "policyDefinitionId": "/providers/Microsoft.Authorization/policyDefinitions/34c877ad-507e-4c82-993e-3452a6e0ad3c",
      "parameters": {
        "effect": { "value": "[parameters('denyPublicStorageEffect')]" }
      }
    }
  ]
}
